import React, { useState, useEffect, useRef } from 'react';

const AnimatedLogin = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [emailFocused, setEmailFocused] = useState(false);
  const [eyesCovered, setEyesCovered] = useState(false);

  // Referencias para los elementos SVG
  const armLRef = useRef(null);
  const armRRef = useRef(null);
  const bodyBGRef = useRef(null);

  const coverEyes = () => {
    if (armLRef.current && armRRef.current) {
      // Reset any ongoing animations
      armLRef.current.style.transition = 'transform 0.45s ease-out';
      armRRef.current.style.transition = 'transform 0.45s ease-out';
      
      // Move arms to cover eyes
      armLRef.current.style.transform = 'translate(-93px, 10px) rotate(0deg)';
      armRRef.current.style.transform = 'translate(-93px, 10px) rotate(0deg)';
      
      // Make arms visible
      armLRef.current.style.visibility = 'visible';
      armRRef.current.style.visibility = 'visible';
      
      setEyesCovered(true);
    }
  };

  const uncoverEyes = () => {
    if (armLRef.current && armRRef.current) {
      // Animate arms back down
      armLRef.current.style.transition = 'transform 1.35s ease-out';
      armRRef.current.style.transition = 'transform 1.35s ease-out';
      
      armLRef.current.style.transform = 'translate(0, 220px) rotate(105deg)';
      armRRef.current.style.transform = 'translate(0, 220px) rotate(-105deg)';
      
      // Hide arms after animation
      setTimeout(() => {
        if (armLRef.current && armRRef.current) {
          armLRef.current.style.visibility = 'hidden';
          armRRef.current.style.visibility = 'hidden';
        }
      }, 1350);
      
      setEyesCovered(false);
    }
  };

  const handlePasswordFocus = () => {
    if (!eyesCovered) {
      coverEyes();
    }
  };

  const handlePasswordBlur = () => {
    // Small delay to handle checkbox focus
    setTimeout(() => {
      if (!showPassword) {
        uncoverEyes();
      }
    }, 100);
  };

  return (
    <form className="login-form" onSubmit={(e) => e.preventDefault()}>
      <div className="svg-container">
        <div>
          <svg className="my-svg" xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink" viewBox="0 0 200 200">
            {/* ... (resto del SVG igual) ... */}
            
            {/* Añadir los brazos que faltaban */}
            <g className="armL" ref={armLRef} style={{visibility: 'hidden', transformOrigin: 'top left'}}>
              <path fill="#ddf1fa" stroke="#3a5e77" strokeLinecap="round" strokeLinejoin="round" strokeMiterlimit="10" strokeWidth="2.5" d="M121.3 97.4L111 58.7l38.8-10.4 20 36.1z"/>
              <path fill="#ddf1fa" stroke="#3a5e77" strokeLinecap="round" strokeLinejoin="round" strokeMiterlimit="10" strokeWidth="2.5" d="M134.4 52.5l19.3-5.2c2.7-.7 5.4.9 6.1 3.5.7 2.7-.9 5.4-3.5 6.1L146 59.7M160.8 76.5l19.4-5.2c2.7-.7 5.4.9 6.1 3.5.7 2.7-.9 5.4-3.5 6.1l-18.3 4.9M158.3 66.8l23.1-6.2c2.7-.7 5.4.9 6.1 3.5.7 2.7-.9 5.4-3.5 6.1l-23.1 6.2M150.9 58.4l26-7c2.7-.7 5.4.9 6.1 3.5.7 2.7-.9 5.4-3.5 6.1l-21.3 5.7"/>
            </g>
            <g className="armR" ref={armRRef} style={{visibility: 'hidden', transformOrigin: 'top right'}}>
              <path fill="#ddf1fa" stroke="#3a5e77" strokeLinecap="round" strokeLinejoin="round" strokeMiterlimit="10" strokeWidth="2.5" d="M265.4 97.3l10.4-38.6-38.9-10.5-20 36.1z"/>
              <path fill="#ddf1fa" stroke="#3a5e77" strokeLinecap="round" strokeLinejoin="round" strokeMiterlimit="10" strokeWidth="2.5" d="M252.4 52.4l-19.2-5.2c-2.7-.7-5.4.9-6.1 3.5-.7 2.7.9 5.4 3.5 6.1l18.2 4.9M226.3 76.4l-19.4-5.2c-2.7-.7-5.4.9-6.1 3.5-.7 2.7.9 5.4 3.5 6.1l18.3 4.9M228.4 66.7l-23.1-6.2c-2.7-.7-5.4.9-6.1 3.5-.7 2.7.9 5.4 3.5 6.1l23.1 6.2M235.8 58.3l-26-7c-2.7-.7-5.4.9-6.1 3.5-.7 2.7.9 5.4 3.5 6.1l21.3 5.7"/>
            </g>
            
            {/* El resto del SVG permanece igual */}
          </svg>
        </div>
      </div>

      <div className={`input-group inputGroup1 ${emailFocused ? 'focus-with-text' : ''}`}>
        <label htmlFor="loginEmail">Email</label>
        <input
          type="email"
          id="loginEmail"
          maxLength="254"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          onFocus={() => setEmailFocused(true)}
          onBlur={() => {
            if (!email) setEmailFocused(false);
          }}
        />
        <p className="helper helper1">email@domain.com</p>
      </div>

      <div className="input-group inputGroup2">
        <label htmlFor="loginPassword">Password</label>
        <input
          type={showPassword ? 'text' : 'password'}
          id="loginPassword"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          onFocus={handlePasswordFocus}
          onBlur={handlePasswordBlur}
        />
        <label className="show-password-toggle" htmlFor="showPasswordCheck">
          Show
          <input
            id="showPasswordCheck"
            type="checkbox"
            checked={showPassword}
            onChange={(e) => setShowPassword(e.target.checked)}
          />
          <div className="indicator"></div>
        </label>
      </div>

      <div className="input-group inputGroup3">
        <button type="submit">Log in</button>
      </div>
    </form>
  );
};

export default AnimatedLogin;
